  pi: ExtensionAPI,
  ctx: ExtensionContext,
): Promise<void> {
  const git = new GitOperations(pi);
  try {
    if (!(await git.isInsideGitRepo())) {
      ctx.ui.setStatus("pi-git-uncommitted", undefined);
